import{_ as a,o as e,c as o,a4 as r}from"./chunks/framework.BMymQDdR.js";const _=JSON.parse('{"title":"代码编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Code-Editor.md","filePath":"zh/v3/designer/Code-Editor.md","lastUpdated":1780630099000}'),i={name:"v3/designer/Code-Editor.md"},t=r('<h1 id="代码编辑器" tabindex="-1">代码编辑器 <a class="header-anchor" href="#代码编辑器" aria-label="Permalink to &quot;代码编辑器&quot;">​</a></h1><p>ENERGY Designer 内置代码编辑器，基于 WebView 集成 Monaco Editor，支持代码高亮、智能补全、跳转定义等功能。</p><h2 id="编辑器类型" tabindex="-1">编辑器类型 <a class="header-anchor" href="#编辑器类型" aria-label="Permalink to &quot;编辑器类型&quot;">​</a></h2><p>设计器中的代码编辑分为两种形式：</p><h3 id="窗体代码编辑-子标签页" tabindex="-1">窗体代码编辑（子标签页） <a class="header-anchor" href="#窗体代码编辑-子标签页" aria-label="Permalink to &quot;窗体代码编辑（子标签页）&quot;">​</a></h3><p>每个设计窗体包含两个子标签页：</p><ul><li><strong>UI 代码</strong> - 显示自动生成的 <code>.ui.go</code> 文件（只读），包含 UI 布局代码</li><li><strong>用户代码</strong> - 显示用户可编辑的 <code>.go</code> 文件，包含事件处理等业务逻辑代码</li></ul><p>在窗体设计标签页内切换这两个子标签页，即可查看和编辑对应代码。</p><h3 id="独立代码编辑器-主标签页" tabindex="-1">独立代码编辑器（主标签页） <a class="header-anchor" href="#独立代码编辑器-主标签页" aria-label="Permalink to &quot;独立代码编辑器（主标签页）&quot;">​</a></h3><p>非窗体相关的代码文件（如 <code>main.go</code>、<code>resources.go</code> 等）在设计器主标签页中以独立标签页形式打开。</p><h2 id="打开代码文件" tabindex="-1">打开代码文件 <a class="header-anchor" href="#打开代码文件" aria-label="Permalink to &quot;打开代码文件&quot;">​</a></h2><h3 id="从项目管理器打开" tabindex="-1">从项目管理器打开 <a class="header-anchor" href="#从项目管理器打开" aria-label="Permalink to &quot;从项目管理器打开&quot;">​</a></h3><p>在项目管理器的 <strong>src</strong> 树节点下双击文件，即可在编辑器中打开。如果文件属于某个设计窗体，会自动切换到对应窗体的子标签页。</p><h3 id="从定义跳转打开" tabindex="-1">从定义跳转打开 <a class="header-anchor" href="#从定义跳转打开" aria-label="Permalink to &quot;从定义跳转打开&quot;">​</a></h3><p>在代码编辑器中按住 <code>Ctrl</code> 点击函数名或类型名，可跳转到定义所在位置。跳转的文件会在合适的标签页中打开：</p><ul><li><code>.ui.go</code> 文件 → 当前窗体的 UI 代码子标签页</li><li><code>.go</code> 用户文件 → 当前窗体的用户代码子标签页</li><li>其他文件 → 设计器主标签页中的独立编辑器</li></ul><h2 id="编辑器功能" tabindex="-1">编辑器功能 <a class="header-anchor" href="#编辑器功能" aria-label="Permalink to &quot;编辑器功能&quot;">​</a></h2><h3 id="代码高亮" tabindex="-1">代码高亮 <a class="header-anchor" href="#代码高亮" aria-label="Permalink to &quot;代码高亮&quot;">​</a></h3><p>Monaco Editor 自动根据文件类型（<code>.go</code>、<code>.json</code> 等）应用语法高亮。</p><h3 id="智能补全" tabindex="-1">智能补全 <a class="header-anchor" href="#智能补全" aria-label="Permalink to &quot;智能补全&quot;">​</a></h3><p>编辑器支持 Go 语言的智能代码补全，包括：</p><ul><li>关键字补全</li><li>类型和函数名补全</li><li>框架 API 补全</li></ul><h3 id="跳转定义" tabindex="-1">跳转定义 <a class="header-anchor" href="#跳转定义" aria-label="Permalink to &quot;跳转定义&quot;">​</a></h3><p>按住 <code>Ctrl</code> 点击标识符，可跳转到其定义位置。支持跨文件跳转。</p><h3 id="诊断信息" tabindex="-1">诊断信息 <a class="header-anchor" href="#诊断信息" aria-label="Permalink to &quot;诊断信息&quot;">​</a></h3><p>编辑器实时显示代码诊断信息（错误、警告），帮助及时发现和修复问题。</p><h2 id="关闭代码编辑器标签" tabindex="-1">关闭代码编辑器标签 <a class="header-anchor" href="#关闭代码编辑器标签" aria-label="Permalink to &quot;关闭代码编辑器标签&quot;">​</a></h2><p>点击标签页上的关闭按钮即可关闭代码编辑器标签。关闭时：</p><ul><li>文件关闭事件通知编辑器语言服务</li><li>从已打开文件列表中移除</li><li>如果没有剩余标签页，禁用滚动按钮</li></ul>',29),l=[t];function d(h,n,c,s,u,p){return e(),o("div",null,l)}const q=a(i,[["render",d]]);export{_ as __pageData,q as default};
